scwin.f_Retrieve = async function () {
  scwin.txt_saveType = "2";
  scwin.txt_payIdx = "1";
  mxTab.setSelectedTabIndex(0);
  scwin.f_ContentsDisable();
  let searchType = clntDelYn.getValue();
  let searchText = qrySearch.getValue();
  let crnVal = "";
  let busiNmVal = "";
  let clntNoVal = "";
  let clntNmVal = "";
  if (searchType == "0") {
    clntNmVal = searchText;
  } else if (searchType == "1") {
    clntNoVal = searchText;
  } else if (searchType == "2") {
    crnVal = searchText;
  } else if (searchType == "3") {
    busiNmVal = searchText;
  } else {
    return false;
  }
  if (searchText == "") {
    let msgArr = new Array(2);
    msgArr[0] = "검색어";
    msgArr[1] = "글자(숫자) 한(두)";
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_011, msgArr);
    qrySearch.setFocus();
    return false;
  }
  sbm_retrieveAccountCustomer.action = "/cm.bc.clnt.clntmgnt.RetrieveAccountCustomerListCMD.do" + "?clntLupCond=T" + "&coClsCd=" + scwin.vCoClsCd + "&coCd=" + scwin.vCoCd + "&crn=" + crnVal + "&busiNm=" + busiNmVal + "&clntNo=" + clntNoVal + "&clntNm=" + clntNmVal + "&clntDelYn=" + lux_useYn.getValue();
  await $c.sbm.execute($p, sbm_retrieveAccountCustomer);
  $c.gus.cfDisableBtn($p, [b_Cancel, b_Save, bAddRow, bDeleteRow, bUndoRow]);
  $c.gus.cfEnableBtnOnly($p, [b_Create, b_Update]);
};
scwin.sbm_retrieveAccountCustomer_submitdone = async function (e) {
  let rowCnt = ds_accountCustomer.getRowCount();
  if (rowCnt == 0) {
    await $c.win.alert($p, "조회된 데이터가 없습니다.");
    qrySearch.setFocus();
    scwin.f_ContentsDisable();
  } else {
    scwin.txt_clntNo = ds_accountCustomer.getCellData(0, "clntNo");
    scwin.txt_rowCount = ds_accountCustomer.getRowCount();
  }
  if (rowCnt < 1) {} else {
    $c.gus.cfEnableBtnOnly($p, [b_Update]);
  }
  if (rowCnt < 1) {
    ds_payAcnt.removeAll();
    ds_collMoneyCond.removeAll();
    ds_payCond.removeAll();
  }
  $c.gus.cfGoPrevPosition($p, ds_accountCustomer, scwin.pos_clnt);
  scwin.txt_createYn = "0";
  scwin.txt_updateYn = "0";
};
scwin.sbm_retrieveAccountCustomer_submiterror = function (e) {
  $c.gus.cfShowError($p, e);
  scwin.txt_createYn = "0";
  scwin.txt_updateYn = "0";
};
