scwin.f_Save = async function () {
  let vSellClntYn = cbx_sellPchsClntYn.getValue().indexOf("sell") >= 0;
  let vPchsClntYn = cbx_sellPchsClntYn.getValue().indexOf("pchs") >= 0;
  if (ds_collMoneyCond.getCellData(0, "stmtPrdClsCd") == "02") {
    await $c.win.alert($p, "결제 구분은 Bill 수령후를 선택하실 수 없습니다.");
    return 0;
  }
  let rowPos = ds_accountCustomer.getRowPosition();
  if (ds_accountCustomer.getCellData(rowPos, "accountClntKndCd") != "EM") {
    if (vSellClntYn == false && vPchsClntYn == false) {
      await $c.win.alert($p, "매출입구분은 필수입력 사항입니다.");
      return false;
    }
  }
  let vCrn = crn.getValue().trim();
  if (crn.getValue() == "") {
    await $c.win.alert($p, "사업자등록번호는 필수 입력입니다.");
    return;
  }
  if (scwin.vCoCd == "023") {
    // TODO: lc_clntTyp 값 체크
  }
  if (scwin.vCoCd == "017") {
    if (scwin.txt_opusClntNo != "") {
      if (!(await scwin.chkOpusClntNo(clntNo.getValue(), scwin.txt_opusClntNo))) {
        return;
      }
    }
  }
  if (scwin.txt_createYn == "1") {}
  if (ds_accountCustomer.getUpdatedIndex().length == 0 && ds_collMoneyCond.getUpdatedIndex().length == 0 && ds_payCond.getUpdatedIndex().length == 0 && ds_payAcnt.getUpdatedIndex().length == 0) {
    await $c.win.alert($p, "변경된 사항이 없습니다.");
    return;
  }
  let chk = await $c.win.confirm($p, "저장하시겠습니까?");
  if (chk) {
    scwin.pos_clnt = ds_accountCustomer.getRowPosition();
    ds_accountCustomer.setCellData(ds_accountCustomer.getRowPosition(), "coClsCd", scwin.vCoClsCd);
    for (let i = 0; i < ds_accountCustomer.getRowCount(); i++) {
      if (ds_accountCustomer.getRowStatus(i) == "C") {
        ds_accountCustomer.setCellData(i, "clntKndCd", "SA");
        if (vSellClntYn && !vPchsClntYn) {
          ds_accountCustomer.setCellData(i, "busiPchsSellCls", "1");
        }
        if (!vSellClntYn && vPchsClntYn) {
          ds_accountCustomer.setCellData(i, "busiPchsSellCls", "2");
        }
        if (vSellClntYn && vPchsClntYn) {
          ds_accountCustomer.setCellData(i, "busiPchsSellCls", "3");
        }
      }
      ds_accountCustomer.setCellData(i, "originalCrn", ds_accountCustomer.getCellData(i, "crn"));
    }
    scwin.txt_saveType = "3";
    sbm_saveAccountCustomer.action = "/cm.bc.clnt.clntmgnt.SaveAccountCustomerCMD.do";
    await $c.sbm.execute($p, sbm_saveAccountCustomer);
  }
};
