scwin.bytelength = function (bstr) {
  let len = bstr.length;
  for (let ii = 0; ii < bstr.length; ii++) {
    let xx = bstr.substr(ii, 1).charCodeAt(0);
    if (xx > 127) {
      len++;
    }
  }
  return len;
};
