scwin.accountClntKndCd_onchange = function (e) {
  let vAccountClntKndCode = accountClntKndCd.getValue();
  if (vAccountClntKndCode == "BK") {
    $c.gus.cfEnableObj($p, crn_search, true);
    // TODO: emp_search disable

    empNo.setValue("");
    empNm.setValue("");

    // TODO: mandatory 동적 설정
    $c.gus.cfRefreshMandSign($p);
  } else if (vAccountClntKndCode == "EM") {
    // TODO: bank_search disable
    // TODO: emp_search enable

    fncInstCd.setValue("");
    fncInstNm.setValue("");

    // TODO: mandatory 동적 설정
    $c.gus.cfRefreshMandSign($p);
  } else if (vAccountClntKndCode == "GR") {
    // TODO: bank_search disable
    // TODO: emp_search disable

    fncInstCd.setValue("");
    fncInstNm.setValue("");
    empNo.setValue("");
    empNm.setValue("");

    // TODO: mandatory 동적 설정
    $c.gus.cfRefreshMandSign($p);
  }
};
scwin.clntBusiClsCd_onchange = function (e) {
  let vClntBusiClsCdIndex = clntBusiClsCd.getSelectedIndex();
  let vClntNo = ds_accountCustomer.getCellData(ds_accountCustomer.getRowPosition(), "clntNo");
  if (vClntBusiClsCdIndex == 0) {
    // TODO: mandatory 동적 설정
    $c.gus.cfRefreshMandSign($p);
  } else if (vClntBusiClsCdIndex == 1) {
    // TODO: mandatory 동적 설정
    $c.gus.cfRefreshMandSign($p);
  } else if (vClntBusiClsCdIndex == 2 || vClntBusiClsCdIndex == 3) {
    // TODO: mandatory 동적 설정
    $c.gus.cfRefreshMandSign($p);
  }
};
